+        OptionsClass: LinkStyleOptions,
+        nameKey: 'rules.link-style.image-style.name',
+        descriptionKey: 'rules.link-style.image-style.description',
+        optionsKey: 'imageStyle',
+        records,
+      }),
+    ];
+  }
+}
+
+function convertWikiLinks(text: string, options: LinkStyleOptions): string {
+  return text.replace(/(!?)\\[\\[([^\\]\
|]+)(?:\\|([^\\]\
|]*))?\\]\\]/g, (match, embed: string, target: string, display: string | undefined) => {
+    if (embed ? options.imageStyle !== 'markdown' : options.linkStyle !== 'markdown') {
+      return match;
+    }
+
+    if (embed) {
+      const alt = display && !/^\\d+(?:x\\d+)?$/.test(display) ? display : target;
+      return `![${alt}](${target})`;
+    }
+
+    return `[${display ?? defaultHeadingDisplay(target)}](${target})`;
+  });
+}
+
+function convertMarkdownLinks(text: string, options: LinkStyleOptions): string {
+  let result = '';
+  let index = 0;
+  while (index < text.length) {
+    const link = parseMarkdownLink(text, index);
+    if (!link || (link.isImage ? options.imageStyle !== 'wiki' : options.linkStyle !== 'wiki') || link.target.includes('://')) {
+      result += text[index++];
+      continue;
+    }
+
+    const display = link.isImage
+      ? (link.label === '' || link.label === link.target ? '' : `|${link.label}`)
+      : (link.label === link.target || link.label === defaultHeadingDisplay(link.target) ? '' : `|${link.label}`);
+    result += `${link.isImage ? '!' : ''}[[${link.target}${display}]]`;
+    index = link.end;
+  }
+  return result;
+}
+
+function parseMarkdownLink(text: string, start: number): MarkdownLink | null {
+  const isImage = text[start] === '!';
+  const labelStart = start + (isImage ? 1 : 0);
+  if (text[labelStart] !== '[') return null;
+
+  const labelEnd = findLabelEnd(text, labelStart);
+  if (labelEnd < 0 || text[labelEnd + 1] !== '(') return null;
+  const label = text.slice(labelStart + 1, labelEnd);
+  if (label.includes('\
') || label.includes('\\r')) return null;
+
+  const destination = parseDestination(text, labelEnd + 2);
+  if (!destination) return null;
+  return {end: destination.end, isImage, label: unescapeMarkdown(label), target: unescapeMarkdown(destination.target)};
+}
+
+function findLabelEnd(text: string, start: number): number {
+  let depth = 0;
+  for (let index = start; index < text.length; index++) {
+    if (text[index] === '\\\') {
+      index++;
+    } else if (text[index] === '[') {
+      depth++;
+    } else if (text[index] === ']' && --depth === 0) {
+      return index;
+    } else if (text[index] === '\
' || text[index] === '\\r') {
+      return -1;
+    }
+  }
+  return -1;
+}
+
+function parseDestination(text: string, start: number): {end: number, target: string} | null {
+  let index = start;
+  while (/[ \	]/.test(text[index] ?? '')) index++;
+  if (text[index] === '<') {
+    const targetStart = ++index;
+    while (index < text.length && text[index] !== '>') {
+      if (text[index] === '\\\') index++;
+      if (text[index] === '\
' || text[index] === '\\r') return null;
+      index++;
+    }
+    if (text[index] !== '>') return null;
+    const target = text.slice(targetStart, index++);
+    while (/[ \	]/.test(text[index] ?? '')) index++;
+    return text[index] === ')' ? {end: index + 1, target} : null;
+  }
+
+  const targetStart = index;
+  let depth = 0;
+  while (index < text.length) {
+    const character = text[index];
+    if (character === '\\\') {
+      index += 2;
+      continue;
+    }
+    if (character === '\
' || character === '\\r' || /[ \	]/.test(character)) return null;
+    if (character === '(') depth++;
+    if (character === ')' && depth-- === 0) return {end: index + 1, target: text.slice(targetStart, index)};
+    index++;
+  }
+  return null;
+}
+
+function unescapeMarkdown(value: string): string {
+  return value.replace(/\\\\(.)/g, '$1');
+}
+
+function defaultHeadingDisplay(target: string): string {
+  const headingIndex = target.indexOf('#');
+  if (headingIndex < 0) return target;
+  const page = target.slice(0, headingIndex);
+  const heading = target.slice(headingIndex + 1);
+  return page ? `${page} > ${heading}` : heading;
